// src/routes/stats.ts
var dateStr2 = (d3) => d3.toISOString().slice(0, 10);
var statsRoutes = new Elysia().use(authPlugin).get("/stats", async ({ userId, query, status: status2 }) => {
  const date6 = query.date ?? dateStr2(new Date);
  if (!isValidDateOnly(date6))
    return status2(400, invalidRequest);
  const today = new Date(`${date6}T00:00:00Z`);
  const weekDates = Array.from({ length: 7 }, (_4, i3) => {
    const d3 = new Date(today);
    d3.setUTCDate(d3.getUTCDate() - i3);
    return d3;
  });
  const list = await db2.select().from(habits).where(and(eq(habits.userId, userId), eq(habits.archived, false)));
  const allChecks = list.length ? await db2.select().from(checks3).where(inArray(checks3.habitId, list.map((h3) => h3.id))) : [];
  let todayDone = 0, todayTotal = 0, weekDone = 0, weekTotal = 0, bestStreak = 0;
  for (const h3 of list) {
    const byDate = new Map(allChecks.filter((c4) => c4.habitId === h3.id).map((c4) => [c4.date, c4.count]));
    for (const d3 of weekDates) {
      if (h3.days[d3.getUTCDay()] !== "1")
        continue;
      const done = (byDate.get(dateStr2(d3)) ?? 0) >= h3.goal;
      weekTotal++;
      if (done)
        weekDone++;
      if (dateStr2(d3) === date6) {
        todayTotal++;
        if (done)
          todayDone++;
      }
    }
    bestStreak = Math.max(bestStreak, streak(h3, byDate, date6));
  }
  const weekStart = dateStr2(weekDates[6]);
  const sessionsThisWeek = await db2.select().from(sessions).where(and(eq(sessions.userId, userId), gte(sessions.startedAt, weekStart)));
  return {
    todayDone,
    todayTotal,
    weekPercent: weekTotal === 0 ? 0 : Math.round(weekDone / weekTotal * 100),
    bestStreak,
    sessionsThisWeek: sessionsThisWeek.length
  };
}, { query: t.Object({ date: t.Optional(dateOnly) }) });

// src/plugins/logging.ts
var starts = new WeakMap;
